"use client"

import * as React from "react"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
  TableCaption,
  Delta,
  formatNumber,
} from "@gunjo/ui"
import { compareLines, type CompareLine } from "./data"

// 現行 vs 改正案。コスト系は「増=悪」なので Delta の tones を反転。
function tonesFor(line: CompareLine) {
  return line.goodWhenUp
    ? { positive: "success" as const, negative: "destructive" as const, zero: "muted" as const }
    : { positive: "destructive" as const, negative: "success" as const, zero: "muted" as const }
}

function fmt(line: CompareLine, v: number) {
  if (line.unit === "円") return formatNumber(v)
  return v % 1 === 0 ? String(v) : v.toFixed(1)
}

export function CompareTable() {
  return (
    <Table>
      <TableCaption>渋88系統：現行ダイヤ と 2026年度 春改正案 の比較（平日・全日）</TableCaption>
      <TableHeader>
        <TableRow>
          <TableHead>指標</TableHead>
          <TableHead className="text-right">現行</TableHead>
          <TableHead className="text-right">改正案</TableHead>
          <TableHead className="text-right">増減</TableHead>
          <TableHead>備考</TableHead>
        </TableRow>
      </TableHeader>
      <TableBody>
        {compareLines.map((line) => (
          <TableRow key={line.label}>
            <TableCell className="font-medium">{line.label}</TableCell>
            <TableCell className="text-right tabular-nums text-muted-foreground">
              {fmt(line, line.now)}
              <span className="ml-0.5 text-xs">{line.unit}</span>
            </TableCell>
            <TableCell className="text-right font-semibold tabular-nums">
              {fmt(line, line.next)}
              <span className="ml-0.5 text-xs text-muted-foreground">{line.unit}</span>
            </TableCell>
            <TableCell className="text-right">
              <Delta
                value={Number((line.next - line.now).toFixed(1))}
                tones={tonesFor(line)}
                format={(v) =>
                  `${v > 0 ? "+" : v < 0 ? "−" : ""}${fmt(line, Math.abs(v))}${line.unit}`
                }
              />
            </TableCell>
            <TableCell className="text-xs text-muted-foreground">{line.note ?? "—"}</TableCell>
          </TableRow>
        ))}
      </TableBody>
    </Table>
  )
}

