import * as React from "react"
import {
  Stringline,
  type StringlineRun,
  type StringlineStop,
  ToggleGroup,
  ToggleGroupItem,
  Badge,
  Cluster,
} from "@gunjo/ui"
import { stopsByRoute, tripsByRoute, toMin, type Direction } from "./data"

type DirFilter = "all" | Direction

/**
 * 運行図表 / ダイヤグラム — 距離×時間の運行図表。
 * @gunjo/ui の <Stringline> を直接利用。停留所=距離軸、便=斜めの運行線。
 * formatTime / onSelect の関数 props を渡すため "use client" 境界に隔離。
 */
export function RunDiagram({ routeId }: { routeId: string }) {
  const [dir, setDir] = React.useState<DirFilter>("all")
  const [selectedRunId, setSelectedRunId] = React.useState<string | number | undefined>(undefined)

  const stopList = stopsByRoute[routeId] ?? stopsByRoute.shibu88
  const trips = tripsByRoute[routeId] ?? tripsByRoute.shibu88

  const stops: StringlineStop[] = stopList.map((s) => ({
    id: s.id,
    label: s.name,
    distance: s.km,
  }))

  const runs: StringlineRun[] = trips
    .filter((t) => dir === "all" || t.direction === dir)
    .map((t) => ({
      id: t.id,
      label: `${t.no}便`,
      direction: t.direction,
      points: stopList
        .filter((s) => t.times[s.id] != null)
        .map((s) => ({ stopId: s.id, time: toMin(t.times[s.id]) })),
      onSelect: () => setSelectedRunId((cur) => (cur === t.id ? undefined : t.id)),
    }))

  const selected = trips.find((t) => t.id === selectedRunId)

  return (
    <div className="flex flex-col gap-3">
      <Cluster justify="between" align="center" className="flex-wrap gap-2">
        <ToggleGroup
          type="single"
          value={dir}
          onValueChange={(v) => v && setDir(v as DirFilter)}
          size="sm"
          aria-label="方向の絞り込み"
        >
          <ToggleGroupItem value="all">全便</ToggleGroupItem>
          <ToggleGroupItem value="down">下り（渋谷→新橋）</ToggleGroupItem>
          <ToggleGroupItem value="up">上り（新橋→渋谷）</ToggleGroupItem>
        </ToggleGroup>

        <Cluster gap={2} align="center" className="text-xs text-muted-foreground">
          <Badge variant="info">上り</Badge>
          <Badge variant="default">下り</Badge>
          <span>運行線をクリックで便を選択</span>
        </Cluster>
      </Cluster>

      <Stringline
        stops={stops}
        runs={runs}
        startTime={toMin("06:00")}
        endTime={toMin("08:00")}
        tickInterval={15}
        height={300}
        selectedRunId={selectedRunId}
        ariaLabel="渋88系統 運行図表（距離×時間）。停留所を縦軸、時刻を横軸に、各便を斜めの運行線で表示。"
      />

      <div
        aria-live="polite"
        className="min-h-[2.25rem] rounded-md border border-border bg-muted/30 px-3 py-2 text-xs text-muted-foreground"
      >
        {selected ? (
          <span className="text-foreground">
            選択中：<strong className="font-semibold">{selected.no}便</strong>（
            {selected.direction === "down" ? "下り" : "上り"}） 始発 {selected.start} → 終着{" "}
            {selected.end}／所要 {toMin(selected.end) - toMin(selected.start)} 分／直前便との間隔{" "}
            {selected.headway} 分／充当行路 {selected.working}
          </span>
        ) : (
          <span>運行線をクリックすると便の詳細（始発・所要・運行間隔・行路）を表示します。</span>
        )}
      </div>
    </div>
  )
}

