import * as React from "react"
import {
  Gantt,
  Cluster,
  Badge,
  MetadataList,
  type GanttRow,
  type GanttItem,
  type MetadataListItem,
} from "@gunjo/ui"
import { workings, workItems, type WorkItem, type WorkSegKind } from "./data"

// 当日の営業日（時刻のみ意味を持つ。Gantt は当日内の時:分で位置決め）。
const SERVICE_DATE = "2026-04-01"
const SERVICE_END = "2026-04-01" // 単一営業日。dayWidth を広げて時間帯を可読化。

const KIND_TONE: Record<WorkSegKind, "muted" | "primary" | "info" | "warning" | "default"> = {
  出庫: "muted",
  運行: "primary",
  折返: "muted",
  入庫: "muted",
  休憩: "default",
}

function toItem(w: WorkItem): GanttItem {
  return {
    id: w.id,
    rowId: w.workingId,
    start: `${SERVICE_DATE}T${w.start}`,
    end: `${SERVICE_DATE}T${w.end}`,
    label: w.label,
    tone: "primary",
    segments: w.segments.map((s) => ({
      start: `${SERVICE_DATE}T${s.start}`,
      end: `${SERVICE_DATE}T${s.end}`,
      label: s.label,
      kind: s.kind,
      tone: s.tone ?? KIND_TONE[s.kind],
    })),
  }
}

export function WorkingsGantt() {
  const [selected, setSelected] = React.useState<WorkItem | null>(null)

  const rows: GanttRow[] = workings.map((w) => ({
    id: w.id,
    label: w.label,
    sublabel: w.sublabel,
  }))

  const items: GanttItem[] = workItems.map(toItem)

  const detail: MetadataListItem[] = selected
    ? [
        { label: "行路", value: selected.label },
        { label: "出庫", value: selected.start },
        { label: "入庫", value: selected.end },
        {
          label: "拘束時分",
          value: `${diffMin(selected.start, selected.end)} 分`,
        },
        {
          label: "運行便数",
          value: `${selected.segments.filter((s) => s.kind === "運行").length} 便`,
        },
      ]
    : []

  return (
    <div className="flex flex-col gap-3">
      <Cluster gap={3} align="center" className="flex-wrap text-xs text-muted-foreground">
        <span className="font-medium text-foreground">凡例</span>
        <Cluster gap={1} align="center">
          <span className="inline-block h-3 w-3 rounded-sm border border-primary/40 bg-primary/15" />
          運行
        </Cluster>
        <Cluster gap={1} align="center">
          <span className="inline-block h-3 w-3 rounded-sm border border-border bg-muted" />
          出入庫・折返
        </Cluster>
        <Cluster gap={1} align="center">
          <span className="inline-block h-3 w-3 rounded-sm border border-warning-border bg-warning-subtle" />
          折返時分不足
        </Cluster>
        <span className="ml-auto">※ 各行路 = 出庫→運行→折返→…→入庫（単一営業日・05:40〜08:30）</span>
      </Cluster>

      <Gantt
        rows={rows}
        items={items}
        startDate={`${SERVICE_DATE}T05:30`}
        endDate={`${SERVICE_END}T09:00`}
        dayWidth={1100}
        rowLabelWidth={120}
        laneHeight={30}
        label="渋88系統 車両運用（行路）"
        onSelectItem={(it) => {
          const w = workItems.find((x) => x.id === it.id) ?? null
          setSelected(w)
        }}
      />

      <div className="rounded-md border border-border bg-muted/30 p-3" aria-live="polite">
        {selected ? (
          <div className="flex flex-col gap-2">
            <Cluster gap={2} align="center">
              <Badge variant="info">選択中</Badge>
              <span className="text-sm font-semibold">{selected.label} 行路</span>
            </Cluster>
            <MetadataList items={detail} layout="horizontal" />
          </div>
        ) : (
          <span className="text-xs text-muted-foreground">
            行路バーをクリックすると拘束時分・運行便数を表示します。
          </span>
        )}
      </div>
    </div>
  )
}

function diffMin(start: string, end: string): number {
  const [sh, sm] = start.split(":").map(Number)
  const [eh, em] = end.split(":").map(Number)
  return eh * 60 + em - (sh * 60 + sm)
}
